import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.CQYuu_FX.js";const S=JSON.parse('{"title":"決済設定","description":"","frontmatter":{"title":"決済設定"},"headers":[],"relativePath":"tenant/21-stripe-full.md","filePath":"tenant/21-stripe-full.md"}'),l={name:"tenant/21-stripe-full.md"};function i(o,t,n,h,s,p){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_21-決済設定" tabindex="-1">21. 決済設定 <a class="header-anchor" href="#_21-決済設定" aria-label="Permalink to &quot;21. 決済設定&quot;">​</a></h1><p>決済設定では、POSLAの月額契約と、セルフ会計・テイクアウトで使う <strong>POSLA決済</strong> を確認します。</p><p>通常の店頭レジでは、店舗がすでに契約しているカード端末・QR決済・現金をそのまま使います。POSLAは店頭決済を実行せず、支払い方法と会計完了の記録だけを残します。</p><h2 id="決済の種類" tabindex="-1">決済の種類 <a class="header-anchor" href="#決済の種類" aria-label="Permalink to &quot;決済の種類&quot;">​</a></h2><table tabindex="0"><thead><tr><th>種類</th><th>内容</th></tr></thead><tbody><tr><td>POSLA利用料</td><td>POSLAの月額利用料のお支払い</td></tr><tr><td>通常レジ会計</td><td>現金 / 店舗カード端末 / 店舗契約QRで支払いを受け、POSLAには記録だけ残す</td></tr><tr><td>POSLA決済</td><td>セルフ会計・テイクアウトで Stripe Connect 経由のオンライン決済を行う</td></tr><tr><td>取消・返金</td><td>通常レジ会計は記録取消、POSLA決済は決済サービス側の返金処理を伴う</td></tr></tbody></table><h2 id="店舗側で確認すること" tabindex="-1">店舗側で確認すること <a class="header-anchor" href="#店舗側で確認すること" aria-label="Permalink to &quot;店舗側で確認すること&quot;">​</a></h2><ol><li>契約プランと請求先を確認します。</li><li>店頭で使う決済端末・QR決済契約を確認します。</li><li>セルフ会計・テイクアウトを使う場合は、Stripe Connect のオンボーディングを完了します。</li><li>返金時の承認ルールを店舗内で決めます。</li><li>レジ締め時に、外部決済端末の集計とPOSLA上の売上記録を突き合わせます。</li></ol><h2 id="通常レジ会計" tabindex="-1">通常レジ会計 <a class="header-anchor" href="#通常レジ会計" aria-label="Permalink to &quot;通常レジ会計&quot;">​</a></h2><p>通常レジでは、POSLAは決済を実行しません。</p><table tabindex="0"><thead><tr><th>支払い方法</th><th>POSLAで行うこと</th></tr></thead><tbody><tr><td>現金</td><td>預かり金・お釣り・会計完了を記録</td></tr><tr><td>カード</td><td>店舗の外部カード端末で決済完了後、カード会計として記録</td></tr><tr><td>QR</td><td>店舗契約のQR決済で支払い完了後、QR会計として記録</td></tr></tbody></table><p>カード端末やQRアプリ側で支払いが完了していない状態で、POSLAの会計を確定しないでください。</p><h2 id="posla決済" tabindex="-1">POSLA決済 <a class="header-anchor" href="#posla決済" aria-label="Permalink to &quot;POSLA決済&quot;">​</a></h2><p>POSLA決済は、セルフ会計・テイクアウトなど、お客様が画面上で支払いまで完了する機能で使います。</p><ul><li>Stripe Connect を使います。</li><li>店頭レジのカード/QRボタンとは別の機能です。</li><li>Stripe設定が未完了、またはセルフ決済がOFFの場合、お客様画面のお会計ボタンは表示されません。</li></ul><h2 id="返金・取消" tabindex="-1">返金・取消 <a class="header-anchor" href="#返金・取消" aria-label="Permalink to &quot;返金・取消&quot;">​</a></h2><ul><li>通常レジの現金・カード・QRは、POSLA上では会計記録の取消として扱います。実際の返金は、現金手渡しまたは外部決済端末・QRアプリ側で行ってください。</li><li>POSLA決済で完了した支払いは、Stripe側の返金処理が必要です。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>店頭カード決済が完了しない</td><td>POSLAではなく店舗契約のカード端末・決済会社の状態を確認してください。</td></tr><tr><td>QR決済が完了しない</td><td>QR決済アプリ・端末側の入金確認画面を確認してください。</td></tr><tr><td>セルフ会計のお会計ボタンが出ない</td><td>Stripe Connect設定とセルフ決済ON/OFFを確認してください。</td></tr><tr><td>返金できない</td><td>通常レジ会計かPOSLA決済かを確認し、通常レジ会計は外部決済側で返金してください。</td></tr></tbody></table>',18)])])}const P=a(l,[["render",i]]);export{S as __pageData,P as default};
